theorem encode_two_terms_in_one_morphism {alpha : Type*} {Γ delta : Type*} [Category Γ] [Category delta] (A : Γ ⥤ Type*) (P : A ⥤ Γ) (a : A.obj Γ) (b : A.obj Γ) (f : delta ⥤ Γ) :
  let a_semicolon_b : A.obj Γ := a;b;
  let a_f : A.obj delta := a[f];
  let b_f : A.obj delta := b[f];
  let P_A : A.obj Γ → Γ := fun x => P.obj (A.map (P.hom x));
  let P_Aa : A.obj Γ → Γ := fun x => P.obj (A.map (P.hom (a;b)));
  let P_A_A : A.obj Γ → A.obj Γ := fun x => A.map (P.hom x);
  let P_Aa_A : A.obj Γ → A.obj Γ := fun x => A.map (P.hom (a;b));
  a_semicolon_b = (a;b) ∧
  (∀ g : A.obj Γ, (g ∘ P_Aa = a ∧ g ∘ P_A_A = b) → g = a_semicolon_b) ∧
  (A.map f ≫ P_Aa_A ∘ a_f;b_f = a_semicolon_b ∘ f)

