theorem id_equiv {Γ delta : Type*} {A : Γ → Type*} {A' : delta → Type*} {f : Γ → delta} {g : delta → Γ}
    {s1 s2 : ∀ gamma, A gamma} {t1 t2 : ∀ delta, A' delta} {r1 r2 : ∀ gamma, f gamma (s1 gamma) = t1 (f gamma) ∧ f gamma (s2 gamma) = t2 (f gamma)}
