    IsHomotopyEquiv (fun gamma p => (r1 gamma).1⁻1 ▸ f gamma p ▸ (r1 gamma).2,
                     fun gamma p' => p' (s1 gamma)⁻1 ▸ g gamma ((r1 gamma).1 ▸ p' ▸ (r1 gamma).2⁻1) ▸ p' (s2 gamma))

