\label{id equiv}
Let us assume that we are given a context homotopy equivalence $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ between $\gamma:\Gamma$ and $\delta:\Delta$ and judgements: $$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type} \textnormal{ and } \boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$$ together with a homotopy equivalence $(f;g)$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$. Moreover let us assume that we are given judgements: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;s_1(\gamma),s_2(\gamma):A(\gamma)$\\ $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;t_1(\delta),t_2(\delta):A'(\delta)$\end{center} together with: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;\mathsf{r}_1(\gamma):f(\gamma,s_1(\gamma))=t_1(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;\mathsf{r}_2(\gamma):f(\gamma,s_2(\gamma))=t_2(\textnormal{\texttt{f}}(\gamma)).$\end{center}

If we name: \begin{center} $\boldsymbol{\lfloor}\gamma:\Gamma,p : s_1(\gamma)=s_2(\gamma)\boldsymbol{\rfloor}\;f^=(\gamma,p)\equiv \mathsf{r}_1(\gamma)^{-1}\bullet f(\gamma,p)\bullet \mathsf{r}_2(\gamma):t_1(\textnormal{\texttt{f}}(\gamma))=t_2(\textnormal{\texttt{f}}(\gamma))$

\smallskip

$\boldsymbol{\lfloor}\gamma:\Gamma,\underline{p}':t_1(\textnormal{\texttt{f}}(\gamma))=t_2(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g^=(\gamma,\underline{p}')\equiv p(\gamma,s_1(\gamma))^{-1}\bullet g(\gamma,\mathsf{r}_1(\gamma)\bullet\underline{p}'\bullet \mathsf{r}_2(\gamma)^{-1})\bullet p(\gamma,s_2(\gamma)):s_1(\gamma)=s_2(\gamma)$
\end{center} then $(f^=;g^=)$ is a homotopy equivalence between $s_1(\gamma)=s_2(\gamma)$ and $t_1(\delta)=t_2(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$.

semantic_equivalence_artifact.original_latex_theorem:
\label{symmetry of canonical equiv}
Suppose that we are given a canonical homotopy equivalence $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ between $\gamma: \Gamma$ and $\delta: \Delta$ and suppose that there is a canonical homotopy equivalence $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ between $\delta$ and $\gamma$ such that $\boldsymbol{\lfloor}\gamma\boldsymbol{\rfloor}\;\textnormal{\texttt{f}}(\gamma)=\textnormal{\texttt{f}}'(\gamma)$ and equivalently $\boldsymbol{\lfloor}\delta\boldsymbol{\rfloor}\;\alpha(\delta):\textnormal{\texttt{g}}(\delta)=\textnormal{\texttt{g}}'(\delta)$.

If we are given judgements: \begin{center}
        $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;S(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;T(\delta):\textsc{Type}$
\end{center} and if there is a canonical homotopy equivalence $\langle\;\phi\;|\;\psi\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:S(\gamma)\boldsymbol{\rfloor}\;\phi(\gamma,x):T(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':T(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;\psi(\gamma,\underline{x}'):S(\gamma)$\end{center} between $S(\gamma)$ and $T(\delta)$ relative to a context homotopy equivalence $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$, then there is a canonical homotopy equivalence $\langle\;\psi'\;|\;\phi'\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:T(\delta)\boldsymbol{\rfloor}\;\psi'(\delta,\underline{x}):S(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':S(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;\phi'(\delta,x'):T(\delta)$\end{center} relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ such that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:T(\delta)\boldsymbol{\rfloor}\;\psi(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*\psi'(\delta,\underline{x})$\\and equivalently $\boldsymbol{\lfloor}\delta:\Delta,x':S(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;\phi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*\phi'(\delta,x')$.\end{center}

\proof By induction on the complexity of $\langle\;\phi\;|\;\psi\;\rangle$.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(a)} then we are done.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(b)} then $S(\gamma)\equiv \Pi_{x:A(\gamma)}B(\gamma,x)$ and $T(\delta)\equiv \Pi_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ for some judgements: \begin{itemize}
        \item $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;B(\gamma,x):\textsc{Type}$
        \item $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;B'(\delta,\underline{x}):\textsc{Type}$
\end{itemize} and there are a canonical homotopy equivalence $\langle\;f_1\;|\;g_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f_1(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g_1(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and a canonical homotopy equivalence $\langle\;f_2\;|\;g_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),y:B(\gamma,x)\boldsymbol{\rfloor}\;f_2(\gamma,x,y):B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))$ \\ $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),\underline{y}':B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))\boldsymbol{\rfloor}\;g_2(\gamma,x,\underline{y}'):B(\gamma,x)$\end{center} between $B(\gamma,x)$ and $B'(\delta,\underline{x})$ relative to the extension $(\textnormal{\texttt{f}},\textnormal{\texttt{f}}_{m+1};\textnormal{\texttt{g}},\textnormal{\texttt{g}}_{n+1})$ of $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ via $(f_1;g_1)$ (\autoref{context homotopy equivalence expansion}), in such a way that the homotopy equivalence $( f^\Pi;g^\Pi)$ of \autoref{pi equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. By inductive hypothesis there are a canonical homotopy equivalence $\langle\;g'_1\;|\;f'_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'_1(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'_1(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ and a canonical homotopy equivalence $\langle\;g'_2\;|\;f'_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,x)\boldsymbol{\rfloor}\;g'_2(\delta,\underline{x},\underline{y}):B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))$ \\ $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))\boldsymbol{\rfloor}\;f'_2(\delta,\underline{x},y'):B'(\delta,\underline{x})$\end{center} between $B'(\delta,\underline{x})$ and $B(\gamma,x)$ relative to the extension $(\textnormal{\texttt{g}}',\textnormal{\texttt{g}}'_{n+1};\textnormal{\texttt{f}}',\textnormal{\texttt{f}}'_{m+1})$ of $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ via $(g'_1;f'_1)$, in such a way that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f_1(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'_1(\delta,x')$\end{center} and that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))\boldsymbol{\rfloor}\;f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')$\end{center} where we remind that: \[\begin{aligned}
    \textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})&\equiv g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})\\
    \textnormal{\texttt{q}}_{n+1}(\delta,\underline{x})&\equiv q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^{-1}
\end{aligned}\] in context $\delta,\underline{x}$, being $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;q_1(\gamma,\underline{x}'):\underline{x}'=f_1(\gamma,g_1(\gamma,\underline{x}'))$. Then $\langle\;g'^\Pi\;|\;f'^\Pi\;\rangle$ is a canonical homotopy equivalence between $\Pi_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ and $\Pi_{x:A(\gamma)}B(\gamma,x)$ and relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$, by \texttt{(b)}. We are left to verify that: $$\boldsymbol{\lfloor}\delta,z':\Pi_{x':A(g'(\delta))}B(\textnormal{\texttt{g}}'(\delta),x')\boldsymbol{\rfloor}\;f^\Pi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*z')=\textnormal{\texttt{q}}(\delta)^*f'^\Pi(\delta,z').$$ Let us observe that $f'^\Pi(\delta,z')\equiv$ \[\begin{aligned}
&\equiv \lambda \underline{x}:A'(\delta).f_2'(\delta,\underline{x},\mathsf{ev}(z',g_1'(\delta,\underline{x})))\\
&=\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*\mathsf{ev}(z',g_1'(\delta,\underline{x})))\\
&=\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),\mathsf{ev}(\alpha(\delta)^*z',g_1(\textnormal{\texttt{g}}(\delta),q(\delta)^*\underline{x})))
\end{aligned}\] in context $\delta,z'$, where the first propositional equality follows by: \begin{center}$\judge{\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))}$\\
${f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')}$\end{center} and the second by: $$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x}).$$ Therefore $q(\delta)^*f'^\Pi(\delta,z')=$ $$\begin{aligned}\text{ }&=q(\delta)^*\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),\mathsf{ev}(\alpha(\delta)^*z',\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})))\\&=\lambda \underline{x}'':A'(\textnormal{\texttt{f}}(\textnormal{\texttt{g}}(\delta))).q_1(\textnormal{\texttt{g}}(\delta),\underline{x}'')^*f_2(\textnormal{\texttt{g}}(\delta),g_1(\textnormal{\texttt{g}}(\delta),\underline{x}''),\mathsf{ev}(\alpha(\delta)^*z',g_1(\textnormal{\texttt{g}}(\delta),\underline{x}'')))\\&\equiv f^\Pi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*z')\end{aligned}$$ in context ${\delta,z'}$, where the first propositional equality follows by propositional function extensionality and propositional functoriality and the second by multiple (generalised) path induction on $q(\delta)$. We are done.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(c)} then as before $S(\gamma)\equiv \Sigma_{x:A(\gamma)}B(\gamma,x)$ and $T(\delta)\equiv \Sigma_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ for some judgements: \begin{itemize}
        \item $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;B(\gamma,x):\textsc{Type}$
        \item $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;B'(\delta,\underline{x}):\textsc{Type}$
\end{itemize} and there are a canonical homotopy equivalence $\langle\;f_1\;|\;g_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f_1(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g_1(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and a canonical homotopy equivalence $\langle\;f_2\;|\;g_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),y:B(\gamma,x)\boldsymbol{\rfloor}\;f_2(\gamma,x,y):B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))$ \\ $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),\underline{y}':B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))\boldsymbol{\rfloor}\;g_2(\gamma,x,\underline{y}'):B(\gamma,x)$\end{center} between $B(\gamma,x)$ and $B'(\delta,\underline{x})$ relative to the extension $(\textnormal{\texttt{f}},\textnormal{\texttt{f}}_{m+1};\textnormal{\texttt{g}},\textnormal{\texttt{g}}_{n+1})$ of $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ via $(f_1;g_1)$ (\autoref{context homotopy equivalence expansion}), in such a way that the homotopy equivalence $( f^\Sigma;g^\Sigma)$ of \autoref{sigma equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. Again, by inductive hypothesis there are a canonical homotopy equivalence $\langle\;g'_1\;|\;f'_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'_1(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'_1(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ and a canonical homotopy equivalence $\langle\;g'_2\;|\;f'_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,x)\boldsymbol{\rfloor}\;g'_2(\delta,\underline{x},\underline{y}):B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))$ \\ $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))\boldsymbol{\rfloor}\;f'_2(\delta,\underline{x},y'):B'(\delta,\underline{x})$\end{center} between $B'(\delta,\underline{x})$ and $B(\gamma,x)$ relative to the extension $(\textnormal{\texttt{g}}',\textnormal{\texttt{g}}'_{n+1};\textnormal{\texttt{f}}',\textnormal{\texttt{f}}'_{m+1})$ of $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ via $(g'_1;f'_1)$, in such a way that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f_1(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'_1(\delta,x')$\end{center} and that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))\boldsymbol{\rfloor}\;f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')$\end{center} where, as before, we remind that: \[\begin{aligned}
    \textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})&\equiv g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})\\
    \textnormal{\texttt{q}}_{n+1}(\delta,\underline{x})&\equiv q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^{-1}
\end{aligned}\] in context $\delta,\underline{x}$, being $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;q_1(\gamma,\underline{x}'):\underline{x}'=f_1(\gamma,g_1(\gamma,\underline{x}'))$. Then $\langle\;g'^\Sigma\;|\;f'^\Sigma\;\rangle$ is a canonical homotopy equivalence between $\Sigma_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ and $\Sigma_{x:A(\gamma)}B(\gamma,x)$ and relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$, by \texttt{(c)}. We are left to verify that: $$\boldsymbol{\lfloor}\delta,\underline{u}:\Sigma_{x':A'(\delta)}B'(\delta,x')\boldsymbol{\rfloor}\;g^\Sigma(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{u})=\alpha(\delta)^*g'^\Sigma(\delta,\underline{u}).$$ Let us observe that: \[\begin{aligned}
    \boldsymbol{\lfloor}\delta,\underline{u}\boldsymbol{\rfloor}\;\alpha_1(\delta,\pi_1\underline{u}):\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u})&=\alpha(\delta)^*g_1'(\delta,\pi_1\underline{u})\\
    \boldsymbol{\lfloor}\delta,\underline{u}\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u})&=(\alpha(\delta),\alpha_1(\delta,\pi_1\underline{u}))^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\\
    &=\alpha_1(\delta,\pi_1\underline{u})^*\alpha(\delta)^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})
\end{aligned}\] where the first equality in the second judgement follows by: \begin{center}
    $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}$\\
    ${g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})}$
\end{center} and the second by (generalised) path induction on $\alpha_1(\delta,\pi_1\underline{u})$. Therefore: $$\begin{aligned} \langle \textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),& g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u}) \rangle\\=&\langle \alpha(\delta)^*g_1'(\delta,\pi_1\underline{u}), \alpha(\delta)^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\rangle\\=&\alpha(\delta)^*\langle g_1'(\delta,\pi_1\underline{u}), g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\rangle\\\equiv& \alpha(\delta)^*g'^\Sigma(\delta,\underline{u}) \end{aligned}$$ in context ${\delta,\underline{u}}$, where the second propositional equality follows by multiple (generalised) path induction on $\alpha(\delta)$. Finally $g^\Sigma(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{u})\equiv$ $$\begin{aligned}\text{ }&\equiv\langle g_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u}), g_2(\textnormal{\texttt{g}}(\delta),g_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u}),q_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u})^*\pi_2\textnormal{\texttt{q}}(\delta)^*\underline{u}) \rangle \\&=\langle \textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}), g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u}) \rangle \end{aligned}$$ in context ${\delta,\underline{u}}$, where the propositional equality follows by multiple (generalised) path induction on $\textnormal{\texttt{q}}(\delta)$ followed by (generalised) path induction on $q_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u})$. We are done.

\medskip

\textit{Notation for the last section of the proof.} Whenever: \begin{center}
$\boldsymbol{\lfloor}\omega:\Omega\boldsymbol{\rfloor}\;x(\omega),y(\omega):O(\omega)$\\ $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha:x(\omega)=y(\omega)$\\ $\boldsymbol{\lfloor}\omega,\omega':\Omega\boldsymbol{\rfloor}\;p:\omega'=\omega$ \end{center} we denote as $p^*\alpha:x(\omega')=y(\omega')$ the usual transport of the term $\alpha(\omega)$ from the type $x(\omega)=y(\omega)$ to the type $x(\omega')=y(\omega')$. However, the operation $p^*$ is defined on the terms of $O(\omega)$ as well, hence the terms $p^*x(\omega),p^*y(\omega):O(\omega')$ are defined. Therefore the operation $p^*$ might be extended as usual to a propositional functor from $O(\omega)$ to $O(\omega')$ and a term $p^*\alpha: p^*x(\omega)=p^*y(\omega)$ is defined. In the last section, in order to distinguish between the terms: \begin{center} $p^*\alpha:x(\omega')=y(\omega')$ and $p^*\alpha:p^*x(\omega)=p^*y(\omega)$ \end{center} that we usually indicate by the same notation, we indicate the \textit{latter} as $\underline{p^*\alpha}$. Observe that: \begin{center}
    $\boldsymbol{\lfloor}p:\omega'=\omega\boldsymbol{\rfloor}\;$ $\begin{tikzcd}x(\omega') \arrow[d, Rightarrow, "x(p)"'] \arrow[r, Rightarrow, "p^*\alpha"] & y(\omega') \arrow[d, Rightarrow, "y(p)"] \\ p^*x(\omega) \arrow[r, Rightarrow, "\underline{p^*\alpha}"'] & p^*y(\omega). \arrow[shorten <=14pt, shorten >=14pt, Rightarrow, no head, from=2-1, to=1-2] \end{tikzcd}$
\end{center} In order to verify this, since $\mathsf{r}(\omega')^*\alpha=\alpha$ and since $x(\mathsf{r}(\omega'))$ and $y(\mathsf{r}(\omega'))$ are propositionally equal to the canonical proofs $\xi(x(\omega'))$ and $\xi(y(\omega'))$ that $x(\omega')=\mathsf{r}(\omega')^*x(\omega')$ and $y(\omega')=\mathsf{r}(\omega')^*y(\omega')$ and by path induction, it is enough to verify that: \begin{center}
    $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;$ $\begin{tikzcd}x(\omega') \arrow[d, Rightarrow, "\xi(x(\omega'))"'] \arrow[r, Rightarrow, "\alpha"] & y(\omega') \arrow[d, Rightarrow, "\xi(y(\omega'))"] \\ \mathsf{r}(\omega')^*x(\omega') \arrow[r, Rightarrow, "\underline{\mathsf{r}(\omega')^*\alpha}"'] & \mathsf{r}(\omega')^*y(\omega'). \arrow[shorten <=21pt, shorten >=21pt, Rightarrow, no head, from=2-1, to=1-2] \end{tikzcd}$
\end{center} which is true because $\xi(-)$ is a homotopy.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(d)} then $S(\gamma)\equiv s_1(\gamma)=s_2(\gamma)$ and $T(\delta)\equiv t_1(\delta)=t_2(\delta)$ for some judgements: \begin{center}
$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$
\end{center} and some judgements:
\begin{center} $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;s_1(\gamma),s_2(\gamma):A(\gamma)$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;t_1(\delta),t_2(\delta):A'(\delta)$\end{center} and there are a canonical homotopy equivalence $\langle\;f\;|\;g\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and judgements: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;r_1(\gamma):f(\gamma,s_1(\gamma))=t_1(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;r_2(\gamma):f(\gamma,s_2(\gamma))=t_2(\textnormal{\texttt{f}}(\gamma)).$\end{center} in such a way that the homotopy equivalence $(f^=,g^=)$ of \autoref{id equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. By inductive hypothesis there is a canonical homotopy equivalence $\langle\;g'\;|\;f'\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ such that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'(\delta,x')$.\end{center} For $i \in \{1,2\}$, let us observe that in context $\delta$: \begin{center}
    $\alpha_1(\delta,t_i(\delta))^{-1}:\alpha(\delta)^*g'(\delta,t_i(\delta))=g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*t_i(\delta))$\\
    $g(\textnormal{\texttt{g}}(\delta),t_i(\textnormal{\texttt{q}}(\delta))^{-1}):g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*t_i(\delta))=g(\textnormal{\texttt{g}}(\delta),t_i(\textnormal{\texttt{f}}(\textnormal{\texttt{g}}(\delta))))$\\
    $g(\textnormal{\texttt{g}}(\delta),r_i(\textnormal{\texttt{g}}(\delta))^{-1}):g(\textnormal{\texttt{g}}(\delta),t_i(\textnormal{\texttt{f}}(\textnormal{\texttt{g}}(\delta))))=g(\textnormal{\texttt{g}}(\delta),f(\textnormal{\texttt{g}}(\delta),s_i(\textnormal{\texttt{g}}(\delta))))$\\
    $p(\textnormal{\texttt{g}}(\delta),s_i(\textnormal{\texttt{g}}(\delta))):g(\textnormal{\texttt{g}}(\delta),f(\textnormal{\texttt{g}}(\delta),s_i(\textnormal{\texttt{g}}(\delta))))=s_i(\textnormal{\texttt{g}}(\delta))$\\
    $s_i(\alpha(\gamma)):s_i(\textnormal{\texttt{g}}(\delta))=\alpha(\delta)^*s_i(\textnormal{\texttt{g}}'(\delta))$
\end{center} and let us call $a_i(\delta):\alpha(\delta)^*g'(\delta,t_i(\delta))=\alpha(\delta)^*s_i(\textnormal{\texttt{g}}'(\delta))$. Let $r_i'(\delta):g'(\delta,t_i(\delta))=s_i(\textnormal{\texttt{g}}'(\delta))$ be such that: $$\underline{\alpha(\delta)^*r_i'(\delta)}=a_i(\delta).$$ Hence $\langle\;g'^=\;|\;f'^=\;\rangle$ is a canonical homotopy equivalence between $t_1(\delta)=t_2(\delta)$ and $s_1(\gamma)=s_2(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$, by \texttt{(d)}, and we are left to verify that: $$\boldsymbol{\lfloor}\delta:\Delta,\underline{p}:t_1(\delta)=t_2(\delta)\boldsymbol{\rfloor}\;g^=(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{p})=\alpha(\delta)^*g'^=(\delta,\underline{p})$$ that is in fact true, as $\boldsymbol{\lfloor}\delta,\underline{p}\boldsymbol{\rfloor}\;\alpha(\delta)^*g'^=(\delta,\underline{p})\equiv$ $$\begin{aligned}\;&\equiv\alpha(\delta)^*(r_1'(\delta)^{-1}\bullet  g'(\delta,\underline{p})  \bullet r_2'(\delta))\\
&=s_1(\alpha(\delta))\bullet\underline{\alpha(\delta)^*(r_1'(\delta)^{-1}\bullet  g'(\delta,\underline{p})  \bullet r_2'(\delta))}\bullet s_2(\alpha(\delta))^{-1}\\
&=s_1(\alpha(\delta))\bullet\underline{\alpha(\delta)^*r_1'(\delta)^{-1}}\bullet  \underline{\alpha(\delta)^*g'(\delta,\underline{p})}  \bullet \underline{\alpha(\delta)^*r_2'(\delta)}\bullet s_2(\alpha(\delta))^{-1}\\
&=s_1(\alpha(\delta))\bullet a_1(\gamma)^{-1} \bullet  \underline{\alpha(\delta)^*g'(\delta,\underline{p})}  \bullet a_2(\gamma) \bullet s_2(\alpha(\delta))^{-1}\\
&=p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),t_1(\textnormal{\texttt{q}}(\delta)))\bullet\alpha_1(\delta,t_1(\delta))\bullet \underline{\alpha(\delta)^*g'(\delta,\underline{p})}\;\bullet\\
&\;\;\;\;\;\alpha_1(\delta,t_2(\delta))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),t_2(\textnormal{\texttt{q}}(\delta))^{-1}) \bullet g(\textnormal{\texttt{g}}(\delta),r_2(\textnormal{\texttt{g}}(\delta))^{-1})\bullet p(\textnormal{\texttt{g}}(\delta),s_2(\textnormal{\texttt{g}}(\delta)))\\
&=p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),t_1(\textnormal{\texttt{q}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),\underline{\textnormal{\texttt{q}}(\delta)^*\underline{p}})\;\bullet\\
&\;\;\;\;\; g(\textnormal{\texttt{g}}(\delta),t_2(\textnormal{\texttt{q}}(\delta))^{-1}) \bullet g(\textnormal{\texttt{g}}(\delta),r_2(\textnormal{\texttt{g}}(\delta))^{-1})\bullet p(\textnormal{\texttt{g}}(\delta),s_2(\textnormal{\texttt{g}}(\delta)))\\
&=p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),t_1(\textnormal{\texttt{q}}(\delta))\bullet \underline{\textnormal{\texttt{q}}(\delta)^*\underline{p}}\bullet t_2(\textnormal{\texttt{q}}(\delta))^{-1})\;\bullet\\
&\;\;\;\;\; g(\textnormal{\texttt{g}}(\delta),r_2(\textnormal{\texttt{g}}(\delta))^{-1})\bullet p(\textnormal{\texttt{g}}(\delta),s_2(\textnormal{\texttt{g}}(\delta)))\\
&=p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{p})\;\bullet\\
&\;\;\;\;\; g(\textnormal{\texttt{g}}(\delta),r_2(\textnormal{\texttt{g}}(\delta))^{-1})\bullet p(\textnormal{\texttt{g}}(\delta),s_2(\textnormal{\texttt{g}}(\delta)))\\
&= p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta))\bullet\textnormal{\texttt{q}}(\delta)^*\underline{p}\bullet r_2(\textnormal{\texttt{g}}(\delta))^{-1})\bullet p(\textnormal{\texttt{g}}(\delta),s_2(\textnormal{\texttt{g}}(\delta)))\\
&\equiv g^=(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{p})
\end{aligned}$$ hence we are done.\endproof

context_pack.original_latex_theorem:
\label{symmetry of canonical equiv}
Suppose that we are given a canonical homotopy equivalence $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ between $\gamma: \Gamma$ and $\delta: \Delta$ and suppose that there is a canonical homotopy equivalence $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ between $\delta$ and $\gamma$ such that $\boldsymbol{\lfloor}\gamma\boldsymbol{\rfloor}\;\textnormal{\texttt{f}}(\gamma)=\textnormal{\texttt{f}}'(\gamma)$ and equivalently $\boldsymbol{\lfloor}\delta\boldsymbol{\rfloor}\;\alpha(\delta):\textnormal{\texttt{g}}(\delta)=\textnormal{\texttt{g}}'(\delta)$.

If we are given judgements: \begin{center}
        $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;S(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;T(\delta):\textsc{Type}$
\end{center} and if there is a canonical homotopy equivalence $\langle\;\phi\;|\;\psi\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:S(\gamma)\boldsymbol{\rfloor}\;\phi(\gamma,x):T(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':T(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;\psi(\gamma,\underline{x}'):S(\gamma)$\end{center} between $S(\gamma)$ and $T(\delta)$ relative to a context homotopy equivalence $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$, then there is a canonical homotopy equivalence $\langle\;\psi'\;|\;\phi'\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:T(\delta)\boldsymbol{\rfloor}\;\psi'(\delta,\underline{x}):S(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':S(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;\phi'(\delta,x'):T(\delta)$\end{center} relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ such that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:T(\delta)\boldsymbol{\rfloor}\;\psi(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*\psi'(\delta,\underline{x})$\\and equivalently $\boldsymbol{\lfloor}\delta:\Delta,x':S(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;\phi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*\phi'(\delta,x')$.\end{center}

\proof By induction on the complexity of $\langle\;\phi\;|\;\psi\;\rangle$.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(a)} then we are done.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(b)} then $S(\gamma)\equiv \Pi_{x:A(\gamma)}B(\gamma,x)$ and $T(\delta)\equiv \Pi_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ for some judgements: \begin{itemize}
        \item $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;B(\gamma,x):\textsc{Type}$
        \item $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;B'(\delta,\underline{x}):\textsc{Type}$
\end{itemize} and there are a canonical homotopy equivalence $\langle\;f_1\;|\;g_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f_1(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g_1(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and a canonical homotopy equivalence $\langle\;f_2\;|\;g_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),y:B(\gamma,x)\boldsymbol{\rfloor}\;f_2(\gamma,x,y):B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))$ \\ $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),\underline{y}':B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))\boldsymbol{\rfloor}\;g_2(\gamma,x,\underline{y}'):B(\gamma,x)$\end{center} between $B(\gamma,x)$ and $B'(\delta,\underline{x})$ relative to the extension $(\textnormal{\texttt{f}},\textnormal{\texttt{f}}_{m+1};\textnormal{\texttt{g}},\textnormal{\texttt{g}}_{n+1})$ of $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ via $(f_1;g_1)$ (\autoref{context homotopy equivalence expansion}), in such a way that the homotopy equivalence $( f^\Pi;g^\Pi)$ of \autoref{pi equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. By inductive hypothesis there are a canonical homotopy equivalence $\langle\;g'_1\;|\;f'_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'_1(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'_1(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ and a canonical homotopy equivalence $\langle\;g'_2\;|\;f'_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,x)\boldsymbol{\rfloor}\;g'_2(\delta,\underline{x},\underline{y}):B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))$ \\ $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))\boldsymbol{\rfloor}\;f'_2(\delta,\underline{x},y'):B'(\delta,\underline{x})$\end{center} between $B'(\delta,\underline{x})$ and $B(\gamma,x)$ relative to the extension $(\textnormal{\texttt{g}}',\textnormal{\texttt{g}}'_{n+1};\textnormal{\texttt{f}}',\textnormal{\texttt{f}}'_{m+1})$ of $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ via $(g'_1;f'_1)$, in such a way that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f_1(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'_1(\delta,x')$\end{center} and that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))\boldsymbol{\rfloor}\;f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')$\end{center} where we remind that: \[\begin{aligned}
    \textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})&\equiv g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})\\
    \textnormal{\texttt{q}}_{n+1}(\delta,\underline{x})&\equiv q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^{-1}
\end{aligned}\] in context $\delta,\underline{x}$, being $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;q_1(\gamma,\underline{x}'):\underline{x}'=f_1(\gamma,g_1(\gamma,\underline{x}'))$. Then $\langle\;g'^\Pi\;|\;f'^\Pi\;\rangle$ is a canonical homotopy equivalence between $\Pi_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ and $\Pi_{x:A(\gamma)}B(\gamma,x)$ and relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$, by \texttt{(b)}. We are left to verify that: $$\boldsymbol{\lfloor}\delta,z':\Pi_{x':A(g'(\delta))}B(\textnormal{\texttt{g}}'(\delta),x')\boldsymbol{\rfloor}\;f^\Pi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*z')=\textnormal{\texttt{q}}(\delta)^*f'^\Pi(\delta,z').$$ Let us observe that $f'^\Pi(\delta,z')\equiv$ \[\begin{aligned}
&\equiv \lambda \underline{x}:A'(\delta).f_2'(\delta,\underline{x},\mathsf{ev}(z',g_1'(\delta,\underline{x})))\\
&=\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*\mathsf{ev}(z',g_1'(\delta,\underline{x})))\\
&=\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),\mathsf{ev}(\alpha(\delta)^*z',g_1(\textnormal{\texttt{g}}(\delta),q(\delta)^*\underline{x})))
\end{aligned}\] in context $\delta,z'$, where the first propositional equality follows by: \begin{center}$\judge{\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))}$\\
${f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')}$\end{center} and the second by: $$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x}).$$ Therefore $q(\delta)^*f'^\Pi(\delta,z')=$ $$\begin{aligned}\text{ }&=q(\delta)^*\lambda \underline{x}.(\textnormal{\texttt{q}}(\delta)^{-1})^*q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^*f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),\mathsf{ev}(\alpha(\delta)^*z',\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})))\\&=\lambda \underline{x}'':A'(\textnormal{\texttt{f}}(\textnormal{\texttt{g}}(\delta))).q_1(\textnormal{\texttt{g}}(\delta),\underline{x}'')^*f_2(\textnormal{\texttt{g}}(\delta),g_1(\textnormal{\texttt{g}}(\delta),\underline{x}''),\mathsf{ev}(\alpha(\delta)^*z',g_1(\textnormal{\texttt{g}}(\delta),\underline{x}'')))\\&\equiv f^\Pi(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*z')\end{aligned}$$ in context ${\delta,z'}$, where the first propositional equality follows by propositional function extensionality and propositional functoriality and the second by multiple (generalised) path induction on $q(\delta)$. We are done.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(c)} then as before $S(\gamma)\equiv \Sigma_{x:A(\gamma)}B(\gamma,x)$ and $T(\delta)\equiv \Sigma_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ for some judgements: \begin{itemize}
        \item $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;B(\gamma,x):\textsc{Type}$
        \item $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;B'(\delta,\underline{x}):\textsc{Type}$
\end{itemize} and there are a canonical homotopy equivalence $\langle\;f_1\;|\;g_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f_1(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g_1(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and a canonical homotopy equivalence $\langle\;f_2\;|\;g_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),y:B(\gamma,x)\boldsymbol{\rfloor}\;f_2(\gamma,x,y):B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))$ \\ $\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma),\underline{y}':B'(\textnormal{\texttt{f}}(\gamma),f_1(\gamma,x))\boldsymbol{\rfloor}\;g_2(\gamma,x,\underline{y}'):B(\gamma,x)$\end{center} between $B(\gamma,x)$ and $B'(\delta,\underline{x})$ relative to the extension $(\textnormal{\texttt{f}},\textnormal{\texttt{f}}_{m+1};\textnormal{\texttt{g}},\textnormal{\texttt{g}}_{n+1})$ of $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ via $(f_1;g_1)$ (\autoref{context homotopy equivalence expansion}), in such a way that the homotopy equivalence $( f^\Sigma;g^\Sigma)$ of \autoref{sigma equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. Again, by inductive hypothesis there are a canonical homotopy equivalence $\langle\;g'_1\;|\;f'_1\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'_1(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'_1(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ and a canonical homotopy equivalence $\langle\;g'_2\;|\;f'_2\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,x)\boldsymbol{\rfloor}\;g'_2(\delta,\underline{x},\underline{y}):B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))$ \\ $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g'_1(\delta,\underline{x}))\boldsymbol{\rfloor}\;f'_2(\delta,\underline{x},y'):B'(\delta,\underline{x})$\end{center} between $B'(\delta,\underline{x})$ and $B(\gamma,x)$ relative to the extension $(\textnormal{\texttt{g}}',\textnormal{\texttt{g}}'_{n+1};\textnormal{\texttt{f}}',\textnormal{\texttt{f}}'_{m+1})$ of $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ via $(g'_1;f'_1)$, in such a way that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'_1(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f_1(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'_1(\delta,x')$\end{center} and that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),y':B(\textnormal{\texttt{g}}'(\delta),g_1'(\delta,\underline{x}))\boldsymbol{\rfloor}\;f_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*y')=(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*f'_2(\delta,\underline{x},y')$\end{center} where, as before, we remind that: \[\begin{aligned}
    \textnormal{\texttt{g}}_{n+1}(\delta,\underline{x})&\equiv g_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})\\
    \textnormal{\texttt{q}}_{n+1}(\delta,\underline{x})&\equiv q_1(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})^{-1}
\end{aligned}\] in context $\delta,\underline{x}$, being $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;q_1(\gamma,\underline{x}'):\underline{x}'=f_1(\gamma,g_1(\gamma,\underline{x}'))$. Then $\langle\;g'^\Sigma\;|\;f'^\Sigma\;\rangle$ is a canonical homotopy equivalence between $\Sigma_{\underline{x}:A'(\delta)}B'(\delta,\underline{x})$ and $\Sigma_{x:A(\gamma)}B(\gamma,x)$ and relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$, by \texttt{(c)}. We are left to verify that: $$\boldsymbol{\lfloor}\delta,\underline{u}:\Sigma_{x':A'(\delta)}B'(\delta,x')\boldsymbol{\rfloor}\;g^\Sigma(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{u})=\alpha(\delta)^*g'^\Sigma(\delta,\underline{u}).$$ Let us observe that: \[\begin{aligned}
    \boldsymbol{\lfloor}\delta,\underline{u}\boldsymbol{\rfloor}\;\alpha_1(\delta,\pi_1\underline{u}):\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u})&=\alpha(\delta)^*g_1'(\delta,\pi_1\underline{u})\\
    \boldsymbol{\lfloor}\delta,\underline{u}\boldsymbol{\rfloor}\;g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u})&=(\alpha(\delta),\alpha_1(\delta,\pi_1\underline{u}))^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\\
    &=\alpha_1(\delta,\pi_1\underline{u})^*\alpha(\delta)^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})
\end{aligned}\] where the first equality in the second judgement follows by: \begin{center}
    $\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta),\underline{y}:B'(\delta,\underline{x})\boldsymbol{\rfloor}$\\
    ${g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\underline{x}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\underline{x}))^*\underline{y})=(\alpha(\delta),\alpha_1(\delta,\underline{x}))^*g'_1(\delta,\underline{x},\underline{y})}$
\end{center} and the second by (generalised) path induction on $\alpha_1(\delta,\pi_1\underline{u})$. Therefore: $$\begin{aligned} \langle \textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),& g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u}) \rangle\\=&\langle \alpha(\delta)^*g_1'(\delta,\pi_1\underline{u}), \alpha(\delta)^*g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\rangle\\=&\alpha(\delta)^*\langle g_1'(\delta,\pi_1\underline{u}), g_2'(\delta,\pi_1\underline{u},\pi_2\underline{u})\rangle\\\equiv& \alpha(\delta)^*g'^\Sigma(\delta,\underline{u}) \end{aligned}$$ in context ${\delta,\underline{u}}$, where the second propositional equality follows by multiple (generalised) path induction on $\alpha(\delta)$. Finally $g^\Sigma(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{u})\equiv$ $$\begin{aligned}\text{ }&\equiv\langle g_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u}), g_2(\textnormal{\texttt{g}}(\delta),g_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u}),q_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u})^*\pi_2\textnormal{\texttt{q}}(\delta)^*\underline{u}) \rangle \\&=\langle \textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}), g_2(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{g}}_{n+1}(\delta,\pi_1\underline{u}),(\textnormal{\texttt{q}}(\delta),\textnormal{\texttt{q}}_{n+1}(\delta,\pi_1\underline{u}))^*\pi_2\underline{u}) \rangle \end{aligned}$$ in context ${\delta,\underline{u}}$, where the propositional equality follows by multiple (generalised) path induction on $\textnormal{\texttt{q}}(\delta)$ followed by (generalised) path induction on $q_1(\textnormal{\texttt{g}}(\delta),\pi_1\textnormal{\texttt{q}}(\delta)^*\underline{u})$. We are done.

\medskip

\textit{Notation for the last section of the proof.} Whenever: \begin{center}
$\boldsymbol{\lfloor}\omega:\Omega\boldsymbol{\rfloor}\;x(\omega),y(\omega):O(\omega)$\\ $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha:x(\omega)=y(\omega)$\\ $\boldsymbol{\lfloor}\omega,\omega':\Omega\boldsymbol{\rfloor}\;p:\omega'=\omega$ \end{center} we denote as $p^*\alpha:x(\omega')=y(\omega')$ the usual transport of the term $\alpha(\omega)$ from the type $x(\omega)=y(\omega)$ to the type $x(\omega')=y(\omega')$. However, the operation $p^*$ is defined on the terms of $O(\omega)$ as well, hence the terms $p^*x(\omega),p^*y(\omega):O(\omega')$ are defined. Therefore the operation $p^*$ might be extended as usual to a propositional functor from $O(\omega)$ to $O(\omega')$ and a term $p^*\alpha: p^*x(\omega)=p^*y(\omega)$ is defined. In the last section, in order to distinguish between the terms: \begin{center} $p^*\alpha:x(\omega')=y(\omega')$ and $p^*\alpha:p^*x(\omega)=p^*y(\omega)$ \end{center} that we usually indicate by the same notation, we indicate the \textit{latter} as $\underline{p^*\alpha}$. Observe that: \begin{center}
    $\boldsymbol{\lfloor}p:\omega'=\omega\boldsymbol{\rfloor}\;$ $\begin{tikzcd}x(\omega') \arrow[d, Rightarrow, "x(p)"'] \arrow[r, Rightarrow, "p^*\alpha"] & y(\omega') \arrow[d, Rightarrow, "y(p)"] \\ p^*x(\omega) \arrow[r, Rightarrow, "\underline{p^*\alpha}"'] & p^*y(\omega). \arrow[shorten <=14pt, shorten >=14pt, Rightarrow, no head, from=2-1, to=1-2] \end{tikzcd}$
\end{center} In order to verify this, since $\mathsf{r}(\omega')^*\alpha=\alpha$ and since $x(\mathsf{r}(\omega'))$ and $y(\mathsf{r}(\omega'))$ are propositionally equal to the canonical proofs $\xi(x(\omega'))$ and $\xi(y(\omega'))$ that $x(\omega')=\mathsf{r}(\omega')^*x(\omega')$ and $y(\omega')=\mathsf{r}(\omega')^*y(\omega')$ and by path induction, it is enough to verify that: \begin{center}
    $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;$ $\begin{tikzcd}x(\omega') \arrow[d, Rightarrow, "\xi(x(\omega'))"'] \arrow[r, Rightarrow, "\alpha"] & y(\omega') \arrow[d, Rightarrow, "\xi(y(\omega'))"] \\ \mathsf{r}(\omega')^*x(\omega') \arrow[r, Rightarrow, "\underline{\mathsf{r}(\omega')^*\alpha}"'] & \mathsf{r}(\omega')^*y(\omega'). \arrow[shorten <=21pt, shorten >=21pt, Rightarrow, no head, from=2-1, to=1-2] \end{tikzcd}$
\end{center} which is true because $\xi(-)$ is a homotopy.

\medskip

If $\langle\;\phi\;|\;\psi\;\rangle$ is of the form \texttt{(d)} then $S(\gamma)\equiv s_1(\gamma)=s_2(\gamma)$ and $T(\delta)\equiv t_1(\delta)=t_2(\delta)$ for some judgements: \begin{center}
$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;A(\gamma):\textsc{Type}$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;A'(\delta):\textsc{Type}$
\end{center} and some judgements:
\begin{center} $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;s_1(\gamma),s_2(\gamma):A(\gamma)$ \, and \, $\boldsymbol{\lfloor}\delta:\Delta\boldsymbol{\rfloor}\;t_1(\delta),t_2(\delta):A'(\delta)$\end{center} and there are a canonical homotopy equivalence $\langle\;f\;|\;g\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma,x:A(\gamma)\boldsymbol{\rfloor}\;f(\gamma,x):A'(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma,\underline{x}':A'(\textnormal{\texttt{f}}(\gamma))\boldsymbol{\rfloor}\;g(\gamma,\underline{x}'):A(\gamma)$\end{center} between $A(\gamma)$ and $A'(\delta)$ relative to $(\textnormal{\texttt{f}};\textnormal{\texttt{g}})$ and judgements: \begin{center}$\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;r_1(\gamma):f(\gamma,s_1(\gamma))=t_1(\textnormal{\texttt{f}}(\gamma))$\\ $\boldsymbol{\lfloor}\gamma:\Gamma\boldsymbol{\rfloor}\;r_2(\gamma):f(\gamma,s_2(\gamma))=t_2(\textnormal{\texttt{f}}(\gamma)).$\end{center} in such a way that the homotopy equivalence $(f^=,g^=)$ of \autoref{id equiv} is the given $\langle\;\phi\;|\;\psi\;\rangle$. By inductive hypothesis there is a canonical homotopy equivalence $\langle\;g'\;|\;f'\;\rangle$: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;g'(\delta,\underline{x}):A(\textnormal{\texttt{g}}'(\delta))$\\ $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f'(\delta,x'):A'(\delta)$\end{center} between $A'(\delta)$ and $A(\gamma)$ relative to $(\textnormal{\texttt{g}}';\textnormal{\texttt{f}}')$ such that: \begin{center}$\boldsymbol{\lfloor}\delta:\Delta,\underline{x}:A'(\delta)\boldsymbol{\rfloor}\;\alpha_1(\delta,\underline{x}):g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*\underline{x})=\alpha(\delta)^*g'(\delta,\underline{x})$\\i.e. $\boldsymbol{\lfloor}\delta:\Delta,x':A(\textnormal{\texttt{g}}'(\delta))\boldsymbol{\rfloor}\;f(\textnormal{\texttt{g}}(\delta),\alpha(\delta)^*x')=\textnormal{\texttt{q}}(\delta)^*f'(\delta,x')$.\end{center} For $i \in \{1,2\}$, let us observe that in context $\delta$: \begin{center}
    $\alpha_1(\delta,t_i(\delta))^{-1}:\alpha(\delta)^*g'(\delta,t_i(\delta))=g(\textnormal{\texttt{g}}(\delta),\textnormal{\texttt{q}}(\delta)^*t_i(\delta))$\\
