&=p(\textnormal{\texttt{g}}(\delta),s_1(\textnormal{\texttt{g}}(\delta)))^{-1}\bullet g(\textnormal{\texttt{g}}(\delta),r_1(\textnormal{\texttt{g}}(\delta)))\bullet g(\textnormal{\texttt{g}}(\delta),t_1(\textnormal{\texttt{q}}(\delta)))\bullet\alpha_1(\delta,t_1(\delta))\bullet \underline{\alpha(\delta)^*g'(\delta,\underline{p})}\;\bullet\\
