    \end{aligned}\] for some $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ and $\langle\;\textnormal{\texttt{c}}'\;|\;\textnormal{\texttt{d}}'\;\rangle$ canonical $\gamma''\to\gamma'$ and $\delta'''\to\delta''$ respectively. The composition of $\int\textsc{tp}$ sends this diagram to the arrow $[f(\textnormal{\texttt{c}}'(g(\omega''))):\Gamma'']$ of the form: $$([\omega:\Omega],[\boldsymbol{\lfloor}\omega''\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(f(\textnormal{\texttt{c}}'(g(\omega''))))):\textsc{Type}])\to([\gamma:\Gamma],[\boldsymbol{\lfloor}\gamma''\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(\gamma'')):\textsc{Type}]).$$ Now, the arrows $[f(\delta'')]$, $[g(\omega'')]$ and $[f(\textnormal{\texttt{c}}'(g(\omega'')))]$ are sent by $-.-$ to the arrows:
    $$\begin{aligned}
    \relax [\delta'', \underline{x} : A(\textnormal{\texttt{c}}(f(\delta'')))] &\xrightarrow{[f(\delta''),\underline{x}]}[\gamma'',x:A(\textnormal{\texttt{c}}(\gamma''))]\\
    [\omega'',\underline{\underline{x}}:A(\textnormal{\texttt{c}}(f(\textnormal{\texttt{c}}'(g(\omega'')))))]&\xrightarrow{[g(\omega''),\underline{\underline{x}}]}[\delta''',\underline{x}':A(\textnormal{\texttt{c}}(f(\textnormal{\texttt{c}}'(\delta'''))))]\\
    [\omega'',\underline{\underline{x}}:A(\textnormal{\texttt{c}}(f(\textnormal{\texttt{c}}'(g(\omega'')))))]&\xrightarrow{[f(\textnormal{\texttt{c}}'(g(\omega''))),\underline{\underline{x}}]}[\gamma'',x:A(\textnormal{\texttt{c}}(\gamma''))]
    \end{aligned}$$
    of $\mathcal{C}$ respectively. In order to conclude that $-.-$ actually preserves the composition, we are left to verify that the composition of the first and the second of these yields the third. By \autoref{semi destiny}, there is $\langle\;\phi\;|\;\psi\;\rangle$ canonical between $A(\textnormal{\texttt{c}}(f(\textnormal{\texttt{c}}'(\delta'''))))$ and $A(\textnormal{\texttt{c}}(f(\delta'')))$ relative to $\langle\;\textnormal{\texttt{c}}'\;|\;\textnormal{\texttt{d}}'\;\rangle$ and such that $\boldsymbol{\lfloor}\delta''',\underline{x}'\boldsymbol{\rfloor}\;\phi(\delta''',\underline{x}')=\underline{x}'$. Hence, by \autoref{context homotopy equivalence expansion} and by the notion of canonical context homotopy equivalence, there is a canonical context homotopy equivalence $\delta''',\underline{x}'\to\delta'',\underline{x}$ whose first component is $\textnormal{\texttt{c}}'(\delta'''),\phi(\delta''',\underline{x}')$ and therefore the composition of $[f(\delta''),\underline{x}]\circ [g(\omega''),\underline{\underline{x}}]$ is represented by: $$\boldsymbol{\lfloor}\omega'',\underline{\underline{x}}\boldsymbol{\rfloor}\;f(\textnormal{\texttt{c}}'(g(\omega''))),\phi(g(\omega''),\underline{\underline{x}})$$ which is in fact propositionally equal to $\boldsymbol{\lfloor}\omega'',\underline{\underline{x}}\boldsymbol{\rfloor}\;f(\textnormal{\texttt{c}}'(g(\omega''))),\underline{\underline{x}}$ since $\boldsymbol{\lfloor}\omega'',\underline{\underline{x}}\boldsymbol{\rfloor}\;\phi(g(\omega''),\underline{\underline{x}})=\underline{\underline{x}}$. We are done by 1. of \autoref{giocare}.
    \item By 2. of \autoref{giocare}, the identity over $([\gamma],[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}])$ is represented by the judgement $\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;\gamma'$. By definition, it is sent by $-.-$ to the arrow: $$[\gamma',x':A(\textnormal{\texttt{c}}(\gamma'))]\xrightarrow{[\boldsymbol{\lfloor}\gamma',x'\boldsymbol{\rfloor}\;\gamma',x']}[\gamma',x':A(\textnormal{\texttt{c}}(\gamma'))]$$ for some $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ canonical $\gamma'\to\gamma'$. This is in fact the identity of $[\gamma',x':A(\textnormal{\texttt{c}}(\gamma'))]=[\gamma',x:A(\gamma')]$. Hence identities are preserved and we are done.\qedhere
\end{itemize}
\endproof

semantic_equivalence_artifact.original_latex_theorem:
\label{display map family}
    The family $P$ is natural and cartesian.
    \proof\text{ }
\begin{itemize}
    \item \textit{Naturality.} Let us consider an arrow: $$[\boldsymbol{\lfloor}\delta'':\Delta''\boldsymbol{\rfloor}\;f(\delta''):\Gamma'']:([\delta:\Delta],[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}])\to ([\gamma:\Gamma],[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}])$$ in $\int\textsc{tp}$. By 3. of \autoref{giocare}, we can assume without loss of generality that $\delta''\equiv\delta'$ and $\gamma''\equiv\gamma'$. If $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ is canonical between $\gamma'$ and itself, then: \[\begin{aligned}
    \relax [\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}]&=[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(\gamma')):\textsc{Type}]\\
    [\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}]&=[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(f(\delta'))):\textsc{Type}]
\end{aligned}\] Then the images of $[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;f(\delta)':\Gamma']$ via the semantic context extension and via the projection admit the presentations: \[\begin{aligned}
\relax [\delta',x':A(\textnormal{\texttt{c}}(f(\delta')))]&\xrightarrow{[\boldsymbol{\lfloor}\delta',x'\boldsymbol{\rfloor}\;f(\delta'),x']}[\gamma',x:A(\textnormal{\texttt{c}}(\gamma'))]\\
[\delta']&\xrightarrow{[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;f(\delta')]}[\gamma']
\end{aligned}\] and we are left to verify that they commute with $P$, in order to conclude the naturality of $P$ itself. By considering the representatives  $\boldsymbol{\lfloor}\delta',x'\boldsymbol{\rfloor}\;\delta'$ and $\boldsymbol{\lfloor}\gamma',x\boldsymbol{\rfloor}\;\gamma'$ of the $[\delta',x']$-component and the $[\gamma',x]$-component of $P$ respectively, we are done by 1. and 4. of \autoref{giocare}.
\item \textit{Cartesianity.} Again, let us consider an arrow: $$[\boldsymbol{\lfloor}\delta':\Delta'\boldsymbol{\rfloor}\;f(\delta'):\Gamma']:([\delta:\Delta],[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}])\to ([\gamma:\Gamma],[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}])$$ in $\int\textsc{tp}$ (the choice of its representative is justified by 3. of \autoref{giocare}) and let us verify that the commutative square: \[\begin{tikzcd}
	{[\delta',x']} && {[\gamma',x]} \\
	\\
	{[\delta']} && {[\gamma']}
	\arrow["{[f(\delta'),x']}", from=1-1, to=1-3]
	\arrow["{[f(\delta')]}", from=3-1, to=3-3]
	\arrow["{[\delta']}"', from=1-1, to=3-1]
	\arrow["{[\gamma']}", from=1-3, to=3-3]
\end{tikzcd}\] of $\mathcal{C}$ is a pullback of $\mathcal{C}$, being $x':A(\textnormal{\texttt{c}}(f(\delta')))$ and $x:A(\textnormal{\texttt{c}}(\gamma'))$ and being $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ canonical $\gamma\to\gamma'$. Hence, let us assume that we are given two arrows $\chi:[\omega]\to[\delta']$ and $\chi':[\omega]\to[\gamma',x]$ of $\mathcal{C}$ such that:
\[\begin{tikzcd}
	{[\omega]} && {[\gamma',x]} \\
	\\
	{[\delta']} && {[\gamma']}
	\arrow[from=1-1, to=1-3]
	\arrow["{[f(\delta')]}", from=3-1, to=3-3]
	\arrow[from=1-1, to=3-1]
	\arrow["{[\gamma']}", from=1-3, to=3-3]
\end{tikzcd}\] commutes. By 3. of \autoref{giocare} there are representatives of the form: \begin{center} $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta'$ and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_2(\omega):\Gamma',\alpha_3(\omega):A(\textnormal{\texttt{c}}(\alpha_2(\omega)))$ \end{center} of $\chi$ and $\chi'$ respectively and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;p(\omega):f(\alpha_1(\omega))=\alpha_2(\omega)$, by 1. and 4. of \autoref{giocare}. Therefore $p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$ and we obtain a morphism of contexts: $$\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta',\;p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$$ which represents a morphism of semantic contexts $\underline{\chi}:[\omega]\to[\delta',x']$ in $\mathcal{C}$. Post-composing $\underline{\chi}$ via $[\delta',x']\xrightarrow{[\delta']}[\delta']$ and via $[\delta',x']\xrightarrow{[f(\delta'),x']}[\gamma',x]$ we get morphisms $[\omega]\to[\delta']$ and $[\omega]\to[\gamma',x]$ respectively represented by: \begin{center} $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta'$ and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;f(\alpha_1(\omega)):\Gamma',\;p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$ \end{center} respectively (by 4. of \autoref{giocare}). The former is clearly $\chi$, while the latter is $\chi'$ because: \[\begin{aligned}
    \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p(\omega):f(\alpha_1(\omega))=\alpha_2(\omega)\\
    \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p(\omega)^*\alpha_3(\omega)\equiv p(\omega)^*\alpha_3(\omega)
\end{aligned}\] which means (1. of \autoref{giocare}) that the morphisms: $$f(\alpha_1(\omega)),\;p(\omega)^*\alpha_3(\omega)\text{ and }\alpha_2(\omega),\alpha_3(\omega)$$ represent the same arrow of $\mathcal{C}$.

Now, let $\underline{\chi}'$ be a morphism $[\omega]\to[\delta',x']$ such that $[\delta']\underline{\chi}'=\chi$ and $[f(\delta'),x']\underline{\chi}'=\chi'$. By 3. of \autoref{giocare}, the morphism $\underline{\chi}'$ is represented by a morphism of contexts of the form: $$\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\beta_1(\omega):\Delta',\;\beta_2(\omega):A(\textnormal{\texttt{c}}(f(\beta_1(\omega)))).$$ Moreover: \[\begin{aligned} \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_1(\omega):\alpha_1(\omega)=\beta_1(\omega)\\ \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_2(\omega):\alpha_2(\omega)=f(\beta_1(\omega))\\ \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_3(\omega):\alpha_3(\omega)=p_2(\omega)^*\beta_2(\omega) \end{aligned}\] by 1. and 4. or \autoref{giocare}, hence $p_1(\omega):\alpha_1(\omega)=\beta_1(\omega)$ and: \[\begin{aligned}
p(\omega)^*\alpha_3(\omega)&=p(\omega)^*p_2(\omega)^*\beta_2(\omega)\\
&=(p(\omega)\bullet p_2(\omega))^*\beta_2(\omega)\\
&=f(p_1(\omega))^*\beta_2(\omega)\\
&=p_1(\omega)^*\beta_2(\omega)
\end{aligned}\] where the first and the second equalities are instances of propositional functorialities, the fourth holds by multiple (generalised) path induction on $p_1(\omega)$ and the third because $\gamma':\Gamma'$ is an h-elementary context and by \autoref{simpleisset}. Therefore, the judgements $\alpha_1(\omega),\;p(\omega)^*\alpha_3(\omega)$ and $\beta_1(\omega),\beta_2(\omega)$ represent the same arrow $[\omega]\to[\delta',x']$ i.e. $\underline{\chi}=\underline{\chi}'$.\qedhere
\end{itemize}
\endproof

context_pack.original_latex_theorem:
\label{display map family}
    The family $P$ is natural and cartesian.
    \proof\text{ }
\begin{itemize}
    \item \textit{Naturality.} Let us consider an arrow: $$[\boldsymbol{\lfloor}\delta'':\Delta''\boldsymbol{\rfloor}\;f(\delta''):\Gamma'']:([\delta:\Delta],[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}])\to ([\gamma:\Gamma],[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}])$$ in $\int\textsc{tp}$. By 3. of \autoref{giocare}, we can assume without loss of generality that $\delta''\equiv\delta'$ and $\gamma''\equiv\gamma'$. If $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ is canonical between $\gamma'$ and itself, then: \[\begin{aligned}
    \relax [\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}]&=[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(\gamma')):\textsc{Type}]\\
    [\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}]&=[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;A(\textnormal{\texttt{c}}(f(\delta'))):\textsc{Type}]
\end{aligned}\] Then the images of $[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;f(\delta)':\Gamma']$ via the semantic context extension and via the projection admit the presentations: \[\begin{aligned}
\relax [\delta',x':A(\textnormal{\texttt{c}}(f(\delta')))]&\xrightarrow{[\boldsymbol{\lfloor}\delta',x'\boldsymbol{\rfloor}\;f(\delta'),x']}[\gamma',x:A(\textnormal{\texttt{c}}(\gamma'))]\\
[\delta']&\xrightarrow{[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;f(\delta')]}[\gamma']
\end{aligned}\] and we are left to verify that they commute with $P$, in order to conclude the naturality of $P$ itself. By considering the representatives  $\boldsymbol{\lfloor}\delta',x'\boldsymbol{\rfloor}\;\delta'$ and $\boldsymbol{\lfloor}\gamma',x\boldsymbol{\rfloor}\;\gamma'$ of the $[\delta',x']$-component and the $[\gamma',x]$-component of $P$ respectively, we are done by 1. and 4. of \autoref{giocare}.
\item \textit{Cartesianity.} Again, let us consider an arrow: $$[\boldsymbol{\lfloor}\delta':\Delta'\boldsymbol{\rfloor}\;f(\delta'):\Gamma']:([\delta:\Delta],[\boldsymbol{\lfloor}\delta'\boldsymbol{\rfloor}\;B(\delta'):\textsc{Type}])\to ([\gamma:\Gamma],[\boldsymbol{\lfloor}\gamma'\boldsymbol{\rfloor}\;A(\gamma'):\textsc{Type}])$$ in $\int\textsc{tp}$ (the choice of its representative is justified by 3. of \autoref{giocare}) and let us verify that the commutative square: \[\begin{tikzcd}
	{[\delta',x']} && {[\gamma',x]} \\
	\\
	{[\delta']} && {[\gamma']}
	\arrow["{[f(\delta'),x']}", from=1-1, to=1-3]
	\arrow["{[f(\delta')]}", from=3-1, to=3-3]
	\arrow["{[\delta']}"', from=1-1, to=3-1]
	\arrow["{[\gamma']}", from=1-3, to=3-3]
\end{tikzcd}\] of $\mathcal{C}$ is a pullback of $\mathcal{C}$, being $x':A(\textnormal{\texttt{c}}(f(\delta')))$ and $x:A(\textnormal{\texttt{c}}(\gamma'))$ and being $\langle\;\textnormal{\texttt{c}}\;|\;\textnormal{\texttt{d}}\;\rangle$ canonical $\gamma\to\gamma'$. Hence, let us assume that we are given two arrows $\chi:[\omega]\to[\delta']$ and $\chi':[\omega]\to[\gamma',x]$ of $\mathcal{C}$ such that:
\[\begin{tikzcd}
	{[\omega]} && {[\gamma',x]} \\
	\\
	{[\delta']} && {[\gamma']}
	\arrow[from=1-1, to=1-3]
	\arrow["{[f(\delta')]}", from=3-1, to=3-3]
	\arrow[from=1-1, to=3-1]
	\arrow["{[\gamma']}", from=1-3, to=3-3]
\end{tikzcd}\] commutes. By 3. of \autoref{giocare} there are representatives of the form: \begin{center} $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta'$ and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_2(\omega):\Gamma',\alpha_3(\omega):A(\textnormal{\texttt{c}}(\alpha_2(\omega)))$ \end{center} of $\chi$ and $\chi'$ respectively and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;p(\omega):f(\alpha_1(\omega))=\alpha_2(\omega)$, by 1. and 4. of \autoref{giocare}. Therefore $p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$ and we obtain a morphism of contexts: $$\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta',\;p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$$ which represents a morphism of semantic contexts $\underline{\chi}:[\omega]\to[\delta',x']$ in $\mathcal{C}$. Post-composing $\underline{\chi}$ via $[\delta',x']\xrightarrow{[\delta']}[\delta']$ and via $[\delta',x']\xrightarrow{[f(\delta'),x']}[\gamma',x]$ we get morphisms $[\omega]\to[\delta']$ and $[\omega]\to[\gamma',x]$ respectively represented by: \begin{center} $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\alpha_1(\omega):\Delta'$ and $\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;f(\alpha_1(\omega)):\Gamma',\;p(\omega)^*\alpha_3(\omega):A(\textnormal{\texttt{c}}(f(\alpha_1(\omega))))$ \end{center} respectively (by 4. of \autoref{giocare}). The former is clearly $\chi$, while the latter is $\chi'$ because: \[\begin{aligned}
    \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p(\omega):f(\alpha_1(\omega))=\alpha_2(\omega)\\
    \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p(\omega)^*\alpha_3(\omega)\equiv p(\omega)^*\alpha_3(\omega)
\end{aligned}\] which means (1. of \autoref{giocare}) that the morphisms: $$f(\alpha_1(\omega)),\;p(\omega)^*\alpha_3(\omega)\text{ and }\alpha_2(\omega),\alpha_3(\omega)$$ represent the same arrow of $\mathcal{C}$.

Now, let $\underline{\chi}'$ be a morphism $[\omega]\to[\delta',x']$ such that $[\delta']\underline{\chi}'=\chi$ and $[f(\delta'),x']\underline{\chi}'=\chi'$. By 3. of \autoref{giocare}, the morphism $\underline{\chi}'$ is represented by a morphism of contexts of the form: $$\boldsymbol{\lfloor}\omega\boldsymbol{\rfloor}\;\beta_1(\omega):\Delta',\;\beta_2(\omega):A(\textnormal{\texttt{c}}(f(\beta_1(\omega)))).$$ Moreover: \[\begin{aligned} \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_1(\omega):\alpha_1(\omega)=\beta_1(\omega)\\ \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_2(\omega):\alpha_2(\omega)=f(\beta_1(\omega))\\ \boldsymbol{\lfloor}\omega&\boldsymbol{\rfloor}\;p_3(\omega):\alpha_3(\omega)=p_2(\omega)^*\beta_2(\omega) \end{aligned}\] by 1. and 4. or \autoref{giocare}, hence $p_1(\omega):\alpha_1(\omega)=\beta_1(\omega)$ and: \[\begin{aligned}
p(\omega)^*\alpha_3(\omega)&=p(\omega)^*p_2(\omega)^*\beta_2(\omega)\\
&=(p(\omega)\bullet p_2(\omega))^*\beta_2(\omega)\\
&=f(p_1(\omega))^*\beta_2(\omega)\\
&=p_1(\omega)^*\beta_2(\omega)
\end{aligned}\] where the first and the second equalities are instances of propositional functorialities, the fourth holds by multiple (generalised) path induction on $p_1(\omega)$ and the third because $\gamma':\Gamma'$ is an h-elementary context and by \autoref{simpleisset}. Therefore, the judgements $\alpha_1(\omega),\;p(\omega)^*\alpha_3(\omega)$ and $\beta_1(\omega),\beta_2(\omega)$ represent the same arrow $[\omega]\to[\delta',x']$ i.e. $\underline{\chi}=\underline{\chi}'$.\qedhere
\end{itemize}
\endproof
